class Codec:
    def serialize(self, root):
        def _serialize(node):
            if not node:
                return '#'
            return str(node.val) + ',' + _serialize(node.left) + ',' + _serialize(node.right)
        return _serialize(root)

    def deserialize(self, data):
        def _deserialize(nums):
            val = nums.pop(0)
            if val == '#':
                return None
            node = TreeNode(val)
            node.left = _deserialize(nums)
            node.right = _deserialize(nums)
            return node
        return _deserialize(data.split(','))

