def invert_dictionary(d): 
    inverse = dict() 
    for key in d: 
        # Go through the original dictionary 
        val = d[key] 
        # Check if key already exists in the inverse dictionary 
        if val not in inverse: 
            # If not, create a new key-value pair 
            inverse[val] = [key] 
        else: 
            inverse[val].append(key) 
    return inverse

