def textToPigLatin(text):
    words = text.split()
    new_words = []

    for word in words:
        if word[0] in 'aeiou':
            new_word = word + 'ay'
        else:
            new_word = word[1:] + word[0] + 'ay'
        new_words.append(new_word)

