You must implement the solution using exactly this function signature (keep the function name and parameter names unchanged):
def longest_palindrome(s):

output:
def longest_palindrome(s):
    n = len(s)
    T = [[False for i in range(n)] for i in range(n)] 
    maxLength = 0

    # Find palindromes of single characters 
    for i in range(n):
      T[i][i] = True

    # Find palindromes of double characters 
    for i in range(n-1):
      if s[i] == s[i+1]:
        T[i][i+1] = True
        maxLength = 2

    # Find palindromes of length greater than 2 
    for k in range(3, n+1):
      for i in range(n-k+1):
        j = i+k-1
        if s[i] == s[j] and T[i+1][j-1]:
          T[i][j] = True
          maxLength = k

    #Find the start and end of the longest one 
    startIndex=0
    endIndex=0
    for i in range(n):
      for j in range(n):
        if T[i][j] and j-i+1 >= maxLength:
          maxLength = j-i+1
          startIndex = i
          endIndex = j

    longestPalindrome = s[startIndex:endIndex+1]

    return longestPalindrome

