import random

# Build the Markov chain
def build_chain(data):
  chain = {}

  for i in range(len(data)-2):
    key = (data[i], data[i+1])
    value = data[i+2]

    if key in chain:
      chain[key].append(value)
    else:
      chain[key] = [value]

  return chain

# Generate the output
def generate_output(chain, seed):
  output = list(seed)

  while True:
    key = (seed[-2], seed[-1])
    if key not in chain:
      break
    value = random.choice(chain[key])
    output.append(value)
    seed = seed[1:] + [value]

  return ' '.join(output)

