You must implement the solution using exactly this function signature (keep the function name and parameter names unchanged):
def assignmentProblem(costMatrix):

output:
def assignmentProblem(costMatrix): 

    # Variables 
    R = len(costMatrix) 
    C = len(costMatrix[0]) 
    X = [[0 for x in range(C)] for x in range(R)] 

    # Find the minimum element in each row 
    minRowValues = [min(i) for i in costMatrix] 

    # Reduce each column by its minimum element and subtract it from the original costMatrix 
    for i in range(len(costMatrix[0])):
        for j in range(len(costMatrix)): 
            costMatrix[j][i] = costMatrix[j][i] - minRowValues[j] 

    # Find the minimum element in each column 
    minColValues = [min(y) for y in zip(*costMatrix)] 

    # Reduce each row by its minimum element 
    for i in range(len(costMatrix)):
        for j in range(len(costMatrix[0])): 
            costMatrix[i][j] = costMatrix[i][j] - minColValues[j] 

    # Star all minimum element in the reduced costMatrix 
    # Find the indices of all the star elements 
    starsLocations = [] 
    for i in range(R): 
        for j in range(C): 
            if costMatrix[i][j] == 0 and X[i][j] != 1: 
                X[i][j] = "*" 
                starsLocations.append([i, j]) 
    return starsLocations

