def binary_search(arr, target):
    low = 0
    high = len(arr) - 1
    while low <= high:
        mid = (low + high) // 2
        if arr[mid] == target:
            if mid == 0 or arr[mid-1] < target:
                return mid
            else:
                high = mid - 1

        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return -1

