You must implement the solution using exactly this function signature (keep the function name and parameter names unchanged):
def longest_common_subsequence(string1, string2):

output:
def longest_common_subsequence(string1, string2):
    """
    Find the longest common subsequence of two strings.

    Args:
        string1 (str): first string
        string2 (str): second string

    Returns:
        str: longest common subsequence
    """
    m = len(string1)
    n = len(string2)
    dp = [[None]*(n+1) for i in range(m+1)]

    for i in range(m+1):
        for j in range(n+1):
            if i == 0 or j == 0:
                dp[i][j] = 0

            elif string1[i-1] == string2[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1

            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])

    lcs = ''
    i, j = m, n
    while i > 0 and j > 0:
        if string1[i-1] == string2[j-1]:
            lcs += string1[i-1]
            i -= 1
            j -= 1

        elif dp[i-1][j] > dp[i][j-1]:
            i -= 1
        else:
            j -= 1

    return lcs[::-1]

